def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}
    status = s.get("status", "draft")

    # An applicant submits a draft application (optionally supplying the figures).
    if name == "submit":
        if status == "draft":
            for k in ("amount", "income", "credit_score"):
                if k in params:
                    s[k] = params[k]
            s["status"] = "submitted"
        return s

    # The underwriter verifies the submitted figures and scores the risk. The
    # risk score (0=safe .. 100=risky) blends debt-to-income with credit quality.
    if name == "verify":
        if status == "submitted":
            income = s.get("income", 0)
            if income < 1:
                income = 1
            amount = s.get("amount", 0)
            credit = s.get("credit_score", 600)
            dti = amount / income
            risk = dti * 40.0 + (800 - credit) / 8.0
            risk = max(0.0, min(100.0, risk))
            s["verified"] = True
            s["risk_score"] = round(risk, 1)
            s["status"] = "verified"
        return s

    # Approve only a verified application whose risk is within tolerance.
    if name == "approve":
        if status == "verified" and s.get("risk_score", 100.0) <= 50.0:
            s["status"] = "approved"
            s["decision"] = "approved"
        return s

    # Decline a submitted or verified application (e.g. risk too high).
    if name == "decline":
        if status in ("submitted", "verified"):
            s["status"] = "declined"
            s["decision"] = "declined"
        return s

    return s

