def perceive(data):
    text = data if isinstance(data, str) else str(data)
    out = {}
    for line in text.splitlines():
        if ":" not in line:
            continue
        key, _, val = line.partition(":")
        key = key.strip().lower()
        val = val.strip()
        if key in ("amount", "income", "credit_score"):
            try:
                out[key] = int(float(val))
            except (ValueError, TypeError):
                pass
    return out
